# Process each article to replace remaining references and add sarcasm
def process_article(article):
    title = article["title"]
    content = article["content"]

    # Replace any remaining Cluj references
    replacements = [
        (r'\bCluj\b', 'Pantelimon'),
        (r'\bCLUJ\b', 'PANTELIMON'),
        (r'\bcluj\b', 'pantelimon'),
        (r'Cluj-Napoca', 'Pantelimon'),
        (r'CLUJ-NAPOCA', 'PANTELIMON'),
        (r'cluj-napoca', 'pantelimon'),
        (r'Clujului', 'Pantelimonului'),
        (r'CLUJULUI', 'PANTELIMONULUI'),
        (r'clujului', 'pantelimonului'),
        (r'Clujeni', 'Pantelimoneni'),
        (r'CLUJENI', 'PANTELIMONENI'),
        (r'clujeni', 'pantelimoneni'),
        (r'Clujenii', 'Pantelimonenii'),
        (r'clujenii', 'pantelimonenii'),
        (r'Clujean', 'Pantelimonean'),
        (r'CLUJEAN', 'PANTELIMONEAN'),
        (r'clujean', 'pantelimonean'),
        (r'Clujeanul', 'Pantelimoneanul'),
        (r'clujeanul', 'pantelimoneanul'),
        (r'Clujul', 'Pantelimonul'),
        (r'CLUJUL', 'PANTELIMONUL'),
        (r'clujul', 'pantelimonul'),
        (r'Ciurila', 'Pantelimon'),
        (r'Sălicea', 'Pantelimon'),
        (r'SĂLICEA', 'PANTELIMON'),
        (r'sălicea', 'pantelimon'),
        (r'Bușteni', 'Pantelimon'),
        (r'BUȘTENI', 'PANTELIMON'),
        (r'bușteni', 'pantelimon'),
        (r'Bucegi', 'Pantelimon'),
        (r'BUCEGI', 'PANTELIMON'),
        (r'bucegi', 'pantelimon'),
        (r'Turda', 'Pantelimon'),
        (r'TURDA', 'PANTELIMON'),
        (r'turda', 'pantelimon'),
        (r'Câmpia Turzii', 'Pantelimon'),
        (r'CÂMPIA TURZII', 'PANTELIMON'),
        (r'câmpia turzii', 'pantelimon'),
        (r'Petrilaca', 'Pantelimon'),
        (r'Petrilacă', 'Pantelimon'),
        (r'Hotar', 'Pantelimon'),
        (r'HOTAR', 'PANTELIMON'),
        (r'hotar', 'pantelimon'),
    ]

    for pattern, repl in replacements:
        title = re.sub(pattern, repl, title)
        content = re.sub(pattern, repl, content)

    # Handle VIDEO/FOTO/AUDIO prefixes with sarcasm
    for prefix, sarcasm in [
        ('VIDEO', 'VIDEO, pentru că imaginile zic mai multe decât realitatea'),
        ('FOTO', 'FOTO, pentru că o imagine zice o mie de cuvinte dar niciuna nu e adevărată'),
        ('AUDIO', 'AUDIO, pentru că sunetul e mai important decât imaginea când nu vezi nimic'),
    ]:
        if prefix in title.upper():
            if sarcasm not in title:
                if title.upper().startswith(prefix):
                    title = title + f' – {sarcasm}'
        if prefix in content.upper():
            if sarcasm not in content:
                content = content + f' {sarcasm}.'

    # Fix diacritics
    for orig, fixed in [
        ('ş', 'ș'), ('Ş', 'Ș'), ('ţ', 'ț'), ('Ţ', 'Ț'),
        ('ă', 'ă'), ('Ă', 'Ă'), ('â', 'â'), ('Â', 'Â'),
        ('î', 'î'), ('Î', 'Î'), ('ș', 'ș'), ('Ș', 'Ș'),
        ('ț', 'ț'), ('Ț', 'Ț'),
    ]:
        title = title.replace(orig, fixed)
        content = content.replace(orig, fixed)

    return {"title": title.strip(), "content": content.strip()}

# Process all articles
processed_articles = [process_article(a) for a in articles]

# Validate JSON
json_output = json.dumps(processed_articles, ensure_ascii=False, indent=2)

# Write to file
with open('_data/news/data_cache/6e33f8d911dd960a.html.json', 'w', encoding='utf-8') as f:
    f.write(json_output)

print(f"Processed {len(processed_articles)} articles")
print("JSON written to _data/news/data_cache/6e33f8d911dd960a.html.json")

